      "amharic_phonetic": "kahn:  'ahunm 'abétu mothnna tnsa'éhn 'inasbalen: 'inamnhalen: 'iyamesegenh yhn hbst yhnm tswa 'inaḳerblhalen, befīth",
      "tigrinya_script": "",
      "tigrinya_phonetic": ""
